     1→/*
     2→ * ldexp() test harness — prints (mantissa_hex, exponent, output_hex) triples.
     3→ */
     4→
     5→#include <math.h>
     6→#include <stdint.h>
     7→#include <stdio.h>
     8→#include <float.h>
     9→
    10→#ifdef EN_PERF
    11→#define PF_COUNTER
