    29→#ifdef EN_PERF
    30→static volatile double g_acc;
    31→
    32→static void emit(double x, int exp)
    33→{
    34→    volatile double vx = x;   /* prevent constant-folding of literal arguments */
    35→    g_acc += ldexp(vx, exp);
    36→}
    37→
    38→static void emit_u(uint64_t bits, int exp)
    39→{
    40→    emit(u2d(bits), exp);
    41→}
    42→#else
    43→static void emit(double x, int exp)
    44→{
    45→    double r = ldexp(x, exp);
    46→    printf("%016llx %d %016llx\n", (unsigned long long)d2u(x), exp, (unsigned long long)d2u(r));
    47→}
    48→
    49→static void emit_u(uint64_t bits, int exp)
    50→{
    51→    emit(u2d(bits), exp);
    52→}
    53→#endif
    54→
    55→static void test_representative_100(void)
    56→{
    57→    /* --- Section 1: Special IEEE 754 x values (8) --- */
    58→    emit(0.0, 0);
    59→    emit(-0.0, 0);
    60→    emit(0.0, 10);                                    /* zero scaled by positive exp */
    61→    emit_u(0x7ff8000000000000ULL, 0);  /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL, 0);  /* sNaN */
    63→    emit_u(0xfff8000000000000ULL, 0);  /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL, 5);  /* +Inf scaled */
    65→    emit_u(0xfff0000000000000ULL, 5);  /* -Inf scaled */
    66→
    67→    /* --- Section 2: Subnormal x values (8) --- */
    68→    emit_u(0x0000000000000001ULL, 0);   /* min positive subnormal: 2^-1074, exp=0 */
    69→    emit_u(0x8000000000000001ULL, 0);   /* min negative subnormal */
    70→    emit_u(0x0008000000000000ULL, 0);   /* mid positive subnormal */
    71→    emit_u(0x8008000000000000ULL, 0);   /* mid negative subnormal */
    72→    emit_u(0x000fffffffffffffULL, 0);   /* max subnormal: just below DBL_MIN */
    73→    emit_u(0x800fffffffffffffULL, 0);   /* max negative subnormal */
    74→    emit_u(0x0000000000000001ULL, 1074); /* min subnormal scaled to 1.0 */
    75→    emit_u(0x000fffffffffffffULL, 1);   /* max subnormal scaled up by 2 */
    76→
    77→    /* --- Section 3: Normal boundary x values (8) --- */
    78→    emit(DBL_MIN, 0);                                 /* 2^-1022, smallest normal */
    79→    emit(-DBL_MIN, 0);
    80→    emit_u(0x0010000000000001ULL, 0);  /* one ULP above DBL_MIN */
    81→    emit(DBL_MAX, 0);                                 /* 0x7fefffffffffffff */
    82→    emit(-DBL_MAX, 0);
    83→    emit(DBL_MIN, 1);                                 /* DBL_MIN * 2 */
    84→    emit(DBL_MIN, -1);                                /* DBL_MIN / 2 -> subnormal */
    85→    emit_u(0x7fefffffffffffffULL, 0);  /* one ULP below DBL_MAX */
    86→
    87→    /* --- Section 4: Near 1.0 x values (8) --- */
    88→    emit_u(0x3fefffffffffffffULL, 0);  /* one ULP below 1.0 */
    89→    emit(1.0, 0);
    90→    emit_u(0x3ff0000000000001ULL, 0);  /* one ULP above 1.0 */
    91→    emit(1.0, 1);                                     /* 1.0 * 2 = 2.0 */
    92→    emit(1.0, -1);                                    /* 1.0 / 2 = 0.5 */
    93→    emit(-1.0, 0);
    94→    emit_u(0xbfefffffffffffffULL, 0);  /* one ULP toward zero from -1.0 */
    95→    emit_u(0xbff0000000000001ULL, 0);  /* one ULP away from zero from -1.0 */
    96→
    97→    /* --- Section 5: Powers-of-2 x with varied exp (10) --- */
    98→    emit(1.0, 2);
    99→    emit(1.0, 10);
   100→    emit(1.0, -2);
   101→    emit(1.0, -10);
   102→    emit(0.5, 1);                                     /* 0.5 * 2 = 1.0 */
   103→    emit(2.0, -1);                                    /* 2.0 / 2 = 1.0 */
   104→    emit(4.0, -2);                                    /* 4.0 / 4 = 1.0 */
   105→    emit(8.0, -3);                                    /* 8.0 / 8 = 1.0 */
   106→    emit(1.0, 52);                                    /* 2^52: mantissa precision boundary */
   107→    emit(1.0, -52);
   108→
   109→    /* --- Section 6: Fractional mantissas with varied exp (8) --- */
   110→    emit(0.5, 0);
   111→    emit(1.5, 0);
   112→    emit(1.5, 1);
   113→    emit(1.5, -1);
   114→    emit(1.25, 4);
   115→    emit(1.75, -4);
   116→    emit(0.75, 3);
   117→    emit(-1.5, 5);
   118→
   119→    /* --- Section 7: Boundary exponents - overflow/underflow thresholds (12) --- */
   120→    emit(1.0, 1023);     /* near overflow: result = 2^1023 */
   121→    emit(1.0, 1022);     /* 2^1022 */
   122→    emit(1.0, 1024);     /* overflow: result = +Inf */
   123→    emit(1.0, 2000);     /* far overflow */
   124→    emit(1.0, -1022);    /* 2^-1022 = DBL_MIN */
   125→    emit(1.0, -1023);    /* one below DBL_MIN -> subnormal */
   126→    emit(1.0, -1074);    /* underflow threshold: 2^-1074 = min subnormal */
   127→    emit(1.0, -1075);    /* underflow: 0 */
   128→    emit(1.0, -2000);    /* far underflow */
   129→    emit(-1.0, 1024);    /* overflow negative */
   130→    emit(-1.0, -1075);   /* underflow negative */
   131→    emit(1.5, 1023);     /* 1.5 * 2^1023 = overflow */
   132→
   133→    /* --- Section 8: Negative x with varied exp (8) --- */
   134→    emit(-0.5, 0);
   135→    emit(-1.0, 1);
   136→    emit(-2.0, -1);
   137→    emit(-1.5, 10);
   138→    emit(-1.5, -10);
   139→    emit(-4.0, -2);
   140→    emit(-1.0, -1022);   /* -> -DBL_MIN */
   141→    emit(-1.0, 1023);    /* -> -2^1023 */
   142→
   143→    /* --- Section 9: Large x with large/small exp (8) --- */
   144→    emit(1.0e50, 0);
   145→    emit(1.0e100, 0);
   146→    emit(1.0e200, 0);
   147→    emit(1.0e-200, 0);
   148→    emit(1.0e50, -200);
   149→    emit(1.0e-50, 200);
   150→    emit(DBL_MAX / 2.0, 1);    /* half of DBL_MAX scaled up: result = DBL_MAX */
   151→    emit(-DBL_MAX / 4.0, 2);   /* -DBL_MAX/4 * 4 = -DBL_MAX */
   152→
   153→    /* --- Section 10: Mixed mantissa and exponent grid (22) --- */
   154→    emit(0.5, 2);
   155→    emit(0.5, -2);
   156→    emit(0.75, 0);
   157→    emit(0.75, 10);
   158→    emit(1.25, 0);
   159→    emit(1.25, -5);
   160→    emit(1.5, 20);
   161→    emit(1.5, -20);
   162→    emit(1.75, 0);
   163→    emit(1.75, 7);
   164→    emit(2.0, 0);
   165→    emit(2.0, 50);
   166→    emit(2.0, -50);
   167→    emit(-0.75, 5);
   168→    emit(-1.25, 3);
   169→    emit(-1.75, -3);
   170→    emit(1.0e-10, 0);
   171→    emit(-1.0e-10, 0);
   172→    emit(1.0e10, 0);
   173→    emit(-1.0e10, 0);
   174→    emit(1.0, 100);
   175→    emit(1.0, -100);
   176→}
