   180→/* 9. Random sweep: 300 (mantissa, exponent) pairs */
   181→#ifndef EN_PERF
   182→static void test_random_300(void)
   183→{
   184→    double mantissas[] = { 0.5, 0.75, 1.0, 1.25, 1.5, 1.75, 2.0, -0.5, -1.0, -1.5 };
   185→    int nm = 10;
   186→    int ne = 30;
   187→    for (int i = 0; i < nm; i++) {
   188→        for (int j = 0; j < ne; j++) {
   189→            int exp = -14 + j;
   190→            emit(mantissas[i], exp);
   191→        }
   192→    }
   193→}
   194→#endif
   195→
   196→/* ------------------------------------------------------------------ */
